  61	enum DRStatus {
  62	  WaitOnUserToCleanUp = Progression.WaitOnUserToCleanUp,
  63	  FailingOver = DRPCStatus.FailingOver,
  64	  Relocating = DRPCStatus.Relocating,
  65	  FailedOver = DRPCStatus.FailedOver,
  66	  Relocated = DRPCStatus.Relocated,
  67	  Critical = VolumeReplicationHealth.CRITICAL,
  68	  Warning = VolumeReplicationHealth.WARNING,
  69	  Healthy = VolumeReplicationHealth.HEALTHY,
  70	  Protecting = DRProtectionStatus.Protecting,
  71	  ProtectionError = DRProtectionStatus.ProtectionError,
  72	}
  73	
  74	const DR_STATUS_CLASS_NAMES = {
  75	  HEALTHY: 'dr-status-healthy',
  76	  WARNING: 'dr-status-warning',
  77	  CRITICAL: 'dr-status-critical',
  78	  ACTION_NEEDED: 'dr-status-action-needed',
  79	  FAILOVER: 'dr-status-failover',
  80	  RELOCATING: 'dr-status-relocating',
  81	  UNKNOWN: 'dr-status-unknown',
  82	  PROTECTING: 'dr-status-protecting',
  83	  PROTECTION_ERROR: 'dr-status-protection-error',
  84	} as const;
  85	
  86	const shouldShowSyncDetails = ({
  87	  status,
  88	  volumeHealth,
  89	  kubeHealth,
  90	}: {
  91	  status: DRStatus;
  92	  volumeHealth: VolumeReplicationHealth;
  93	  kubeHealth?: VolumeReplicationHealth;
  94	}): boolean => {
  95	  if ([DRStatus.Healthy, DRStatus.Warning, DRStatus.Critical].includes(status))
  96	    return true;
  97	
  98	  if ([DRStatus.FailedOver, DRStatus.Relocated].includes(status)) {
  99	    const isHealthy =
 100	      volumeHealth === VolumeReplicationHealth.HEALTHY &&
 101	      (!kubeHealth || kubeHealth === VolumeReplicationHealth.HEALTHY);
 102	    return !isHealthy;
 103	  }
 104	
 105	  return false;
 106	};
