 254	const handleHealthStatus = ({
 255	  status,
 256	  volumeTitle,
 257	  volumeMsg,
 258	  kubeTitle,
 259	  kubeMsg,
 260	  bothTitle,
 261	  bothMsg,
 262	  volumeReplicationHealth,
 263	  kubeObjectReplicationHealth,
 264	}): StatusContent | null => {
 265	  if (
 266	    volumeReplicationHealth === status &&
 267	    kubeObjectReplicationHealth === status
 268	  ) {
 269	    return {
 270	      icon: getStatusIcon(status),
 271	      title: bothTitle,
 272	      message: bothMsg,
 273	      className: `dr-status-${status.toLowerCase()}`,
 274	      status,
 275	    };
 276	  }
 277	
 278	  if (volumeReplicationHealth === status) {
 279	    return {
 280	      icon: getStatusIcon(status),
 281	      title: volumeTitle,
 282	      message: volumeMsg,
 283	      className: `dr-status-${status.toLowerCase()}`,
 284	      status,
 285	    };
 286	  }
 287	
 288	  if (kubeObjectReplicationHealth === status) {
 289	    return {
 290	      icon: getStatusIcon(status),
 291	      title: kubeTitle,
 292	      message: kubeMsg,
 293	      className: `dr-status-${status.toLowerCase()}`,
 294	      status,
 295	    };
 296	  }
 297	
 298	  return null;
 299	};
