 333	/**
 334	 * Determines whether to show the progression train view based on DR status and progression data.
 335	 * @param status - Current DR status
 336	 * @param progression - Progression string from DRPC status
 337	 * @param action - DR action type (failover or relocate)
 338	 * @returns true if train view should be displayed
 339	 */
 340	const shouldShowProgressionTrainView = (
 341	  status: DRStatus,
 342	  progression?: string,
 343	  action?: DRActionType
 344	): boolean => {
 345	  // Show train view during active operations (FailingOver/Relocating)
 346	  // OR when waiting for cleanup (WaitOnUserToCleanUp) - so user can see train is stuck at cleanup step
 347	  // OR when phase is FailedOver/Relocated but progression is still active (cleanup steps ongoing)
 348	  return (
 349	    [
 350	      DRStatus.FailingOver,
 351	      DRStatus.Relocating,
 352	      DRStatus.WaitOnUserToCleanUp,
 353	      DRStatus.FailedOver,
 354	      DRStatus.Relocated,
 355	    ].includes(status) &&
 356	    isProgressionActive(progression) &&
 357	    !!action
 358	  );
 359	};
