 361	/**
 362	 * Determines if replication is healthy based on volume and kube object health status.
 363	 * @param volumeReplicationHealth - Volume replication health status (required)
 364	 * @param kubeObjectReplicationHealth - Kube object replication health status (optional)
 365	 * @returns true if replication is healthy
 366	 *
 367	 * Note: kubeObjectReplicationHealth is undefined when kube object protection is not configured.
 368	 * In such cases, we treat it as healthy since there's no kube object replication to monitor.
 369	 */
 370	const isReplicationHealthy = (
 371	  volumeReplicationHealth: VolumeReplicationHealth,
 372	  kubeObjectReplicationHealth?: VolumeReplicationHealth
 373	): boolean => {
 374	  const isVolumeHealthy =
 375	    volumeReplicationHealth === VolumeReplicationHealth.HEALTHY;
 376	  const isKubeObjectHealthy =
 377	    !kubeObjectReplicationHealth ||
 378	    kubeObjectReplicationHealth === VolumeReplicationHealth.HEALTHY;
 379	
 380	  return isVolumeHealthy && isKubeObjectHealthy;
 381	};
 382	
 383	const isProgressionActive = (progression?: string): boolean =>
 384	  !!progression && progression !== Progression.Completed;
 385	
 386	const shouldShowActionStatus = ({
 387	  phase,
 388	  progression,
 389	  volumeReplicationHealth,
 390	  kubeObjectReplicationHealth,
 391	}: {
 392	  phase: DRPCStatus;
 393	  progression?: string;
 394	  volumeReplicationHealth: VolumeReplicationHealth;
 395	  kubeObjectReplicationHealth?: VolumeReplicationHealth;
 396	}): boolean => {
 397	  const isCompleted = progression === Progression.Completed;
 398	  const isHealthy = isReplicationHealthy(
 399	    volumeReplicationHealth,
 400	    kubeObjectReplicationHealth
 401	  );
 402	
 403	  switch (phase) {
 404	    case DRPCStatus.FailedOver:
 405	    case DRPCStatus.Relocated:
 406	      return !(isCompleted && isHealthy);
 407	
 408	    case DRPCStatus.FailingOver:
 409	    case DRPCStatus.Relocating:
 410	      return true;
 411	
 412	    default:
 413	      return false;
 414	  }
 415	};
 416	
 417	const shouldShowProtecting = (
 418	  isCleanupRequired: boolean,
 419	  protectedCondition?: K8sResourceCondition,
 420	  volumeLastGroupSyncTime?: string
 421	): boolean => {
 422	  // Never show "Protecting" during cleanup or when condition is missing
 423	  if (isCleanupRequired || !protectedCondition) {
 424	    return false;
 425	  }
 426	
 427	  // If sync has started, protection is already established
 428	  if (volumeLastGroupSyncTime) {
 429	    return false;
 430	  }
 431	
 432	  const { status, reason } = protectedCondition;
 433	
 434	  // Show "Protecting" during initial setup before sync starts
 435	  const isStatusUnknown = status === K8sResourceConditionStatus.Unknown;
 436	  const isReasonUnknown = reason === DRPlacementControlConditionReason.Unknown;
 437	  const isProgressingWithoutSync =
 438	    status === K8sResourceConditionStatus.False &&
 439	    reason === DRPlacementControlConditionReason.Progressing;
 440	
 441	  // Protection is shown when:
 442	  // 1. Status is unknown (validating), OR
 443	  // 2. Reason is unknown (undetermined), OR
 444	  // 3. Protection is progressing but sync hasn't started
 445	  return isStatusUnknown || isReasonUnknown || isProgressingWithoutSync;
 446	};
 447	
 448	const shouldShowProtectionError = (
 449	  protectedCondition?: K8sResourceCondition
 450	): boolean => {
 451	  if (!protectedCondition) return false;
 452	
 453	  const { status, reason } = protectedCondition;
 454	
 455	  // Only show error for Error reasons with actionable statuses
 456	  return (
 457	    reason === DRPlacementControlConditionReason.Error &&
 458	    (status === K8sResourceConditionStatus.True ||
 459	      status === K8sResourceConditionStatus.False)
 460	  );
 461	};
 462	
 463	const getDRStatus = ({
 464	  isCleanupRequired,
 465	  phase,
 466	  volumeReplicationHealth,
 467	  kubeObjectReplicationHealth,
 468	  progression,
 469	  volumeLastGroupSyncTime,
 470	  protectedCondition,
 471	}: {
 472	  isCleanupRequired: boolean;
 473	  phase: DRPCStatus;
 474	  volumeReplicationHealth: VolumeReplicationHealth;
 475	  kubeObjectReplicationHealth?: VolumeReplicationHealth;
 476	  progression?: string;
 477	  volumeLastGroupSyncTime?: string;
 478	  protectedCondition?: K8sResourceCondition;
 479	}): DRStatus => {
 480	  // Check if cleanup is required — this has the highest priority
 481	  if (isCleanupRequired) return DRStatus.WaitOnUserToCleanUp;
 482	
 483	  // Handle failover or relocation phases directly
 484	  if (phase === DRPCStatus.FailingOver) return DRStatus.FailingOver;
 485	  if (phase === DRPCStatus.Relocating) return DRStatus.Relocating;
 486	
 487	  // Combine health statuses into an array for easier checks (filter out undefined)
 488	  const replicationHealths = [
 489	    volumeReplicationHealth,
 490	    ...(kubeObjectReplicationHealth ? [kubeObjectReplicationHealth] : []),
 491	  ];
 492	
 493	  // For FailedOver/Relocated phases:
 494	  // - If sync has started (lastGroupSyncTime exists), show health status unless progression is still active
 495	  // - If sync hasn't started yet, show completion message (phase status)
 496	  // This check must come BEFORE "Protecting" status to ensure completion status
 497	  // is shown immediately after failover/relocate completes, even if protectedCondition
 498	  // is still in "Unknown" or "Progressing" state.
 499	  const hasSyncStarted = !!volumeLastGroupSyncTime;
 500	
 501	  if (phase === DRPCStatus.FailedOver || phase === DRPCStatus.Relocated) {
 502	    // If sync hasn't started yet, show completion message (phase status)
 503	    if (!hasSyncStarted) {
 504	      return phase === DRPCStatus.FailedOver
 505	        ? DRStatus.FailedOver
 506	        : DRStatus.Relocated;
 507	    }
 508	
 509	    // Once sync has started, check if progression is still active before showing health status
 510	    // If progression is active (not Completed/undefined), show phase status to keep progression view visible
 511	    if (isProgressionActive(progression)) {
 512	      return phase === DRPCStatus.FailedOver
 513	        ? DRStatus.FailedOver
 514	        : DRStatus.Relocated;
 515	    }
 516	
 517	    // If any health status is CRITICAL, return Critical status
 518	    if (replicationHealths.includes(VolumeReplicationHealth.CRITICAL))
 519	      return DRStatus.Critical;
 520	
 521	    // If any health status is WARNING, return Warning status
 522	    if (replicationHealths.includes(VolumeReplicationHealth.WARNING))
 523	      return DRStatus.Warning;
 524	
 525	    // If replication is healthy, return Healthy status (not phase status)
 526	    if (
 527	      isReplicationHealthy(volumeReplicationHealth, kubeObjectReplicationHealth)
 528	    ) {
 529	      return DRStatus.Healthy;
 530	    }
 531	
 532	    // Fallback: show Critical if health cannot be determined
 533	    return DRStatus.Critical;
 534	  }
 535	
 536	  // Check for protection error before other statuses (only for non-completion phases)
 537	  if (shouldShowProtectionError(protectedCondition))
 538	    return DRStatus.ProtectionError;
 539	
 540	  // Check for protecting status before health checks (only for non-completion phases)
 541	  // This should NOT apply to FailedOver/Relocated phases as they are handled above
 542	  // Also, if sync has started, we should NOT show "Protecting" - show health status instead
 543	  if (
 544	    shouldShowProtecting(
 545	      isCleanupRequired,
 546	      protectedCondition,
 547	      volumeLastGroupSyncTime
 548	    )
 549	  )
 550	    return DRStatus.Protecting;
 551	
 552	  // For FailingOver/Relocating phases, always show the action status
 553	  if (
 554	    shouldShowActionStatus({
 555	      phase,
 556	      progression,
 557	      volumeReplicationHealth,
 558	      kubeObjectReplicationHealth,
 559	    })
 560	  ) {
 561	    if (phase === DRPCStatus.FailingOver) return DRStatus.FailingOver;
 562	    if (phase === DRPCStatus.Relocating) return DRStatus.Relocating;
 563	  }
 564	
 565	  // For other phases, check health status
 566	  // If any health status is CRITICAL, return Critical status immediately
 567	  if (replicationHealths.includes(VolumeReplicationHealth.CRITICAL))
 568	    return DRStatus.Critical;
 569	
 570	  // If any health status is WARNING, return Warning status
 571	  if (replicationHealths.includes(VolumeReplicationHealth.WARNING))
 572	    return DRStatus.Warning;
 573	
 574	  // If at least one status is HEALTHY (and none were critical or warning), return Healthy status
 575	  if (replicationHealths.includes(VolumeReplicationHealth.HEALTHY))
 576	    return DRStatus.Healthy;
 577	
 578	  // Fallback — assume Critical if no health statuses matched
 579	  return DRStatus.Critical;
 580	};
