 582	const getCleanupMessage = (
 583	  phase: DRPCStatus,
 584	  cluster: string,
 585	  t: TFunction
 586	) => {
 587	  return phase === DRPCStatus.FailedOver
 588	    ? t('Clean up application resources on failed cluster {{cluster}}.', {
 589	        cluster,
 590	      })
 591	    : t(
 592	        'Clean up application resources on the primary cluster {{cluster}} to start relocating.',
 593	        { cluster }
 594	      );
 595	};
