 597	type GetDRStatusDetailsParams = {
 598	  isCleanupRequired: boolean;
 599	  phase: DRPCStatus;
 600	  volumeReplicationHealth: VolumeReplicationHealth;
 601	  kubeObjectReplicationHealth?: VolumeReplicationHealth;
 602	  progression?: string;
 603	  volumeLastGroupSyncTime?: string;
 604	  t: TFunction;
 605	  primaryCluster: string;
 606	  targetCluster: string;
 607	  protectedCondition?: K8sResourceCondition;
 608	};
 609	
 610	const getDRStatusDetails = ({
 611	  isCleanupRequired,
 612	  phase,
 613	  volumeReplicationHealth,
 614	  kubeObjectReplicationHealth,
 615	  progression,
 616	  volumeLastGroupSyncTime,
 617	  t,
 618	  primaryCluster,
 619	  targetCluster,
 620	  protectedCondition,
 621	}: GetDRStatusDetailsParams): StatusContent => {
 622	  const drStatus = getDRStatus({
 623	    isCleanupRequired,
 624	    phase,
 625	    volumeReplicationHealth,
 626	    kubeObjectReplicationHealth,
 627	    progression,
 628	    volumeLastGroupSyncTime,
 629	    protectedCondition,
 630	  });
 631	
 632	  switch (drStatus) {
 633	    case DRStatus.Protecting:
 634	      return createStatus(
 635	        DRStatus.Protecting,
 636	        t('Protecting'),
 637	        protectedCondition?.message ||
 638	          t('Validating application protection. This may take a few minutes.'),
 639	        DR_STATUS_CLASS_NAMES.PROTECTING
 640	      );
 641	
 642	    case DRStatus.ProtectionError:
 643	      return createStatus(
 644	        DRStatus.ProtectionError,
 645	        t('Protection Error'),
 646	        protectedCondition?.message ||
 647	          t('An error occurred during application protection.'),
 648	        DR_STATUS_CLASS_NAMES.PROTECTION_ERROR
 649	      );
 650	
 651	    case DRStatus.Healthy: {
 652	      const title = kubeObjectReplicationHealth
 653	        ? t('All volumes & Kubernetes resources are synced')
 654	        : t('All volumes are synced');
 655	      return createStatus(
 656	        DRStatus.Healthy,
 657	        title,
 658	        null,
 659	        DR_STATUS_CLASS_NAMES.HEALTHY
 660	      );
 661	    }
 662	
 663	    case DRStatus.Warning:
 664	      return (
 665	        handleHealthStatus({
 666	          status: DRStatus.Warning,
 667	          volumeTitle: t('Volumes are syncing slower than usual'),
 668	          volumeMsg: t(
 669	            '1 or more volume groups are affected. Check the network connection, cluster health, or workload status for potential issues.'
 670	          ),
 671	          kubeTitle: t('Kubernetes resources are syncing slower than usual'),
 672	          kubeMsg: t(
 673	            '1 or more Kubernetes resources are affected. Check the network connection, cluster health, or workload status for potential issues.'
 674	          ),
 675	          bothTitle: t(
 676	            'Volumes & Kubernetes resources are syncing slower than usual'
 677	          ),
 678	          bothMsg: t(
 679	            '1 or more volumes & Kubernetes resources are affected. Check the network connection, cluster health, or workload status for potential issues.'
 680	          ),
 681	          volumeReplicationHealth,
 682	          kubeObjectReplicationHealth,
 683	        }) ||
 684	        createStatus(
 685	          DRStatus.Healthy,
 686	          t('Status unknown'),
 687	          t('The current status could not be determined.'),
 688	          DR_STATUS_CLASS_NAMES.UNKNOWN
 689	        )
 690	      );
 691	
 692	    case DRStatus.Critical:
 693	      return (
 694	        handleHealthStatus({
 695	          status: DRStatus.Critical,
 696	          volumeTitle: t('Volumes are not syncing'),
 697	          volumeMsg: t(
 698	            '1 or more volume groups are affected. Check the network connection, cluster health, or workload status for potential issues.'
 699	          ),
 700	          kubeTitle: t('Kubernetes resources are not syncing'),
 701	          kubeMsg: t(
 702	            '1 or more Kubernetes resources are affected. Check the network connection, cluster health, or workload status for potential issues.'
 703	          ),
 704	          bothTitle: t('Volumes & Kubernetes resources are not syncing'),
 705	          bothMsg: t(
 706	            '1 or more volumes & Kubernetes resources are affected. Check the network connection, cluster health, or workload status for potential issues.'
 707	          ),
 708	          volumeReplicationHealth,
 709	          kubeObjectReplicationHealth,
 710	        }) ||
 711	        createStatus(
 712	          DRStatus.Critical,
 713	          t('Status unknown'),
 714	          t('The current status could not be determined.'),
 715	          DR_STATUS_CLASS_NAMES.UNKNOWN
 716	        )
 717	      );
 718	
 719	    case DRStatus.WaitOnUserToCleanUp: {
 720	      // For failover: cleanup is needed on the failed cluster (source before failover)
 721	      //   - After failover, primaryCluster is the NEW cluster (where app moved to, C2)
 722	      //   - targetCluster is the OTHER cluster in DR policy (the failed cluster, C1)
 723	      // For relocate: cleanup is needed on the old primary cluster (source before relocate)
 724	      //   - After relocate, primaryCluster is the NEW cluster (where app moved to)
 725	      //   - targetCluster is the OTHER cluster (the old primary cluster)
 726	      // In both cases, targetCluster is the cluster that needs cleanup
 727	      return createStatus(
 728	        DRStatus.WaitOnUserToCleanUp,
 729	        t('Action needed'),
 730	        getCleanupMessage(phase, targetCluster, t),
 731	        DR_STATUS_CLASS_NAMES.ACTION_NEEDED
 732	      );
 733	    }
 734	
 735	    case DRStatus.FailingOver:
 736	      return createStatus(
 737	        DRStatus.FailingOver,
 738	        t('Failing over application to {{targetCluster}}', { targetCluster }),
 739	        t('Deploying the application on the target cluster.'),
 740	        DR_STATUS_CLASS_NAMES.FAILOVER
 741	      );
 742	
 743	    case DRStatus.Relocating:
 744	      return createStatus(
 745	        DRStatus.Relocating,
 746	        t('Relocating application to {{targetCluster}}', { targetCluster }),
 747	        t('Deploying the application on the target cluster.'),
 748	        DR_STATUS_CLASS_NAMES.RELOCATING
 749	      );
 750	
 751	    case DRStatus.FailedOver: {
 752	      const isHealthy = isReplicationHealthy(
 753	        volumeReplicationHealth,
 754	        kubeObjectReplicationHealth
 755	      );
 756	
 757	      const healthStatusMessage = !isHealthy
 758	        ? t(
 759	            'Replication health is {{health}}. Review sync details below for more information.',
 760	            {
 761	              health:
 762	                volumeReplicationHealth === VolumeReplicationHealth.CRITICAL
 763	                  ? t('Critical')
 764	                  : t('Warning'),
 765	            }
 766	          )
 767	        : null;
 768	
 769	      const completionTitle = t('Failover complete');
 770	      // After failover, primaryCluster is where the app is now running (the failover cluster)
 771	      const completionMessage = t(
 772	        'Application is now running on {{primaryCluster}}.',
 773	        {
 774	          primaryCluster,
 775	        }
 776	      );
 777	
 778	      return createCompletionStatus(
 779	        drStatus,
 780	        completionTitle,
 781	        completionMessage,
 782	        healthStatusMessage,
 783	        isHealthy
 784	          ? DR_STATUS_CLASS_NAMES.HEALTHY
 785	          : DR_STATUS_CLASS_NAMES.WARNING
 786	      );
 787	    }
 788	
 789	    case DRStatus.Relocated: {
 790	      const isHealthy = isReplicationHealthy(
 791	        volumeReplicationHealth,
 792	        kubeObjectReplicationHealth
 793	      );
 794	
 795	      const healthStatusMessage = !isHealthy
 796	        ? t(
 797	            'Replication health is {{health}}. Review sync details below for more information.',
 798	            {
 799	              health:
 800	                volumeReplicationHealth === VolumeReplicationHealth.CRITICAL
 801	                  ? t('Critical')
 802	                  : t('Warning'),
 803	            }
 804	          )
 805	        : null;
 806	
 807	      const completionTitle = t('Relocation complete');
 808	      // After relocate, primaryCluster is where the app is now running (the preferred cluster)
 809	      const completionMessage = t(
 810	        'Application successfully relocated to {{primaryCluster}}.',
 811	        {
 812	          primaryCluster,
 813	        }
 814	      );
 815	
 816	      return createCompletionStatus(
 817	        drStatus,
 818	        completionTitle,
 819	        completionMessage,
 820	        healthStatusMessage,
 821	        isHealthy
 822	          ? DR_STATUS_CLASS_NAMES.HEALTHY
 823	          : DR_STATUS_CLASS_NAMES.WARNING
 824	      );
 825	    }
 826	
 827	    default:
 828	      return createStatus(
 829	        DRStatus.Critical,
 830	        t('Status unknown'),
 831	        t('The current status could not be determined.'),
 832	        DR_STATUS_CLASS_NAMES.UNKNOWN
 833	      );
 834	  }
 835	};
