 837	const DRStatusPopoverBody: React.FC<{
 838	  status: DRStatus;
 839	  message?: string | React.ReactNode;
 840	  disasterRecoveryStatus: DRStatusProps;
 841	  cleanupDocHref?: string;
 842	}> = ({ status, message, disasterRecoveryStatus, cleanupDocHref }) => {
 843	  // Determine which cluster the user should clean up, based on action and phase.
 844	  // - Failover: always clean up the failed/source cluster (the non-primary cluster).
 845	  // - Relocate (discovered apps): cleanup happens first, before migration, on the current primary.
 846	  // - Relocate (managed or post-migration): cleanup happens on the old primary, which is the non-primary cluster.
 847	  const cleanupCluster =
 848	    disasterRecoveryStatus.action === DRActionType.FAILOVER
 849	      ? disasterRecoveryStatus.targetCluster
 850	      : disasterRecoveryStatus.phase === DRPCStatus.Relocating &&
 851	          disasterRecoveryStatus.isDiscoveredApp
 852	        ? disasterRecoveryStatus.primaryCluster
 853	        : disasterRecoveryStatus.targetCluster;
 854	
 855	  if (
 856	    shouldShowProgressionTrainView(
 857	      status,
 858	      disasterRecoveryStatus.progression,
 859	      disasterRecoveryStatus.action
 860	    )
 861	  ) {
 862	    return (
 863	      <ProgressionTrainView
 864	        action={disasterRecoveryStatus.action}
 865	        currentProgression={disasterRecoveryStatus.progression}
 866	        applicationName={
 867	          disasterRecoveryStatus.applicationName || 'Application'
 868	        }
 869	        actionStartTime={disasterRecoveryStatus.actionStartTime}
 870	        progressionDetails={disasterRecoveryStatus.progressionDetails}
 871	        isCleanupRequired={disasterRecoveryStatus.isCleanupRequired}
 872	        cleanupCluster={cleanupCluster}
 873	        isDiscoveredApp={disasterRecoveryStatus.isDiscoveredApp}
 874	        learnMoreHref={cleanupDocHref}
 875	      />
 876	    );
 877	  }
 878	
 879	  return (
 880	    <>
 881	      {message && (
 882	        <Text
 883	          className="dr-status-popover__description"
 884	          data-test-id="popover-description"
 885	        >
 886	          {message}
 887	        </Text>
 888	      )}
 889	      {[
 890	        DRStatus.FailingOver,
 891	        DRStatus.Relocating,
 892	        DRStatus.FailedOver,
 893	        DRStatus.Relocated,
 894	      ].includes(status) && (
 895	        <div className="dr-status-popover__cluster-details">
 896	          <ClusterDetails
 897	            primaryCluster={disasterRecoveryStatus.primaryCluster}
 898	            targetCluster={disasterRecoveryStatus.targetCluster}
 899	            status={status}
 900	          />
 901	        </div>
 902	      )}
 903	    </>
 904	  );
 905	};
